from pydantic_ai._otel_messages import (
    ChatMessage, TextPart, ToolCallPart, 
    ToolCallResponsePart, UriPart, Role
)

# 构建一个多部分消息
message: ChatMessage = {
    'role': 'user',
    'parts': [
        {'type': 'text', 'content': '这张图片里有什么？'},
        {
            'type': 'uri',
            'uri': 'https://example.com/image.jpg',
            'mime_type': 'image/jpeg',
            'modality': 'image'
        }
    ]
}

# 工具调用消息
tool_call: ToolCallPart = {
    'type': 'tool_call',
    'id': 'call_123',
    'name': 'get_weather',
    'arguments': {'city': 'Beijing'}
}

# 工具返回消息
tool_response: ToolCallResponsePart = {
    'type': 'tool_call_response',
    'id': 'call_123',
    'name': 'get_weather',
    'result': {'temperature': 25, 'condition': 'sunny'}
}

